Expo Router brings Next.js-style file-based routing to React Native. Routes are defined by the file structure in the `app/` directory.

```typescript
// app/_layout.tsx — Root layout
import { Stack } from 'expo-router';
import { ThemeProvider } from '@react-navigation/native';

export default function RootLayout() {
  return (
    <ThemeProvider value={colorScheme === 'dark' ? DarkTheme : DefaultTheme}>
      <Stack>
        <Stack.Screen name="(tabs)" options={{ headerShown: false }} />
        <Stack.Screen name="modal" options={{ presentation: 'modal' }} />
        <Stack.Screen name="settings" options={{ title: 'Settings' }} />
      </Stack>
    </ThemeProvider>
  );
}
```

```typescript
// app/(tabs)/_layout.tsx — Tab navigator
import { Tabs } from 'expo-router';
import { Ionicons } from '@expo/vector-icons';

export default function TabLayout() {
  return (
    <Tabs screenOptions={{ tabBarActiveTintColor: '#2563eb' }}>
      <Tabs.Screen
        name="index"
        options={{
          title: 'Home',
          tabBarIcon: ({ color, size }) => <Ionicons name="home" size={size} color={color} />,
        }}
      />
      <Tabs.Screen
        name="profile"
        options={{
          title: 'Profile',
          tabBarIcon: ({ color, size }) => <Ionicons name="person" size={size} color={color} />,
        }}
      />
    </Tabs>
  );
}
```

```typescript
// app/(tabs)/index.tsx — Home screen
import { Link, useRouter } from 'expo-router';
import { View, Text, Pressable } from 'react-native';

export default function HomeScreen() {
  const router = useRouter();

  return (
    <View style={{ flex: 1, padding: 20 }}>
      {/* Declarative navigation */}
      <Link href="/settings" asChild>
        <Pressable><Text>Go to Settings</Text></Pressable>
      </Link>

      {/* Imperative navigation */}
      <Pressable onPress={() => router.push('/profile')}>
        <Text>View Profile</Text>
      </Pressable>

      {/* Dynamic routes */}
      <Link href="/user/123"><Text>User 123</Text></Link>
    </View>
  );
}

// app/user/[id].tsx — Dynamic route
import { useLocalSearchParams } from 'expo-router';

export default function UserScreen() {
  const { id } = useLocalSearchParams<{ id: string }>();
  return <Text>User ID: {id}</Text>;
}
```

Groups like `(tabs)` create layouts without affecting the URL. Use `_layout.tsx` files to define navigation containers (Stack, Tabs, Drawer). Enable typed routes with `expo-router/types` in tsconfig for autocomplete on href values.

Cloudflare Workers run JavaScript at the edge (300+ locations globally) with sub-millisecond cold starts. KV provides global key-value storage.

```typescript
// src/index.ts
import { Hono } from 'hono';
import { cors } from 'hono/cors';
import { cache } from 'hono/cache';

type Bindings = {
  CACHE: KVNamespace;
  API_KEY: string;
};

const app = new Hono<{ Bindings: Bindings }>();

app.use('/*', cors({ origin: 'https://myapp.com' }));

app.get('/api/config/:key', async (c) => {
  const key = c.req.param('key');

  // Check KV cache first
  const cached = await c.env.CACHE.get(key, 'json');
  if (cached) {
    return c.json(cached, 200, { 'X-Cache': 'HIT' });
  }

  // Fetch from origin
  const response = await fetch(`https://api.myapp.com/config/${key}`, {
    headers: { Authorization: `Bearer ${c.env.API_KEY}` },
  });
  const data = await response.json();

  // Cache in KV for 5 minutes
  await c.env.CACHE.put(key, JSON.stringify(data), { expirationTtl: 300 });

  return c.json(data, 200, { 'X-Cache': 'MISS' });
});

app.get('/api/geo', (c) => {
  return c.json({
    country: c.req.header('cf-ipcountry'),
    city: c.req.raw.cf?.city,
    timezone: c.req.raw.cf?.timezone,
    latitude: c.req.raw.cf?.latitude,
    longitude: c.req.raw.cf?.longitude,
  });
});

export default app;
```

**wrangler.toml:**
```toml
name = "my-worker"
main = "src/index.ts"
compatibility_date = "2024-01-01"

[[kv_namespaces]]
binding = "CACHE"
id = "abc123"

[vars]
API_KEY = "secret"  # Use wrangler secret for production
```

```bash
# Deploy
npx wrangler deploy

# Local development
npx wrangler dev
```

Cloudflare Workers have a 10ms CPU time limit on the free plan (50ms on paid). KV is eventually consistent with a 60-second propagation delay. Use Hono for routing — it's designed for edge runtimes and adds minimal overhead.

