**Console logging best practices:**
```typescript
// Use __DEV__ to avoid logging in production
if (__DEV__) {
  console.log('Debug info:', { userId, screen: 'Home' });
}

// Structured logging
const logger = {
  debug: (...args: any[]) => __DEV__ && console.log('[DEBUG]', ...args),
