```

**Network request inspection:**
```typescript
// Use React Native Debugger or Flipper for network inspection
// Or add a fetch interceptor:
if (__DEV__) {
  const originalFetch = global.fetch;
  global.fetch = async (input, init) => {
    const url = typeof input === 'string' ? input : input.url;
    console.log(`[FETCH] ${init?.method || 'GET'} ${url}`);
    const start = Date.now();
    const response = await originalFetch(input, init);
    console.log(`[FETCH] ${response.status} ${url} (${Date.now() - start}ms)`);
    return response;
  };
}
```

**Common debugging issues:**
- Red screen with "Invariant Violation" — usually a missing native module. Run `npx expo install` to fix dependencies.
- Slow performance — check for unnecessary re-renders with `React.Profiler` or `why-did-you-render`.
- Metro bundler cache — clear with `npx expo start --clear`.
- iOS simulator unresponsive — reset with `xcrun simctl shutdown all && xcrun simctl erase all`.

Vercel Edge Functions run at the CDN layer with access to geolocation data. Combined with Next.js middleware, they enable A/B testing and geo-routing without origin latency.

```typescript
// middleware.ts
import { NextRequest, NextResponse } from 'next/server';

export const config = {
  matcher: ['/((?!api|_next|favicon.ico).*)'],
};

export function middleware(req: NextRequest) {
  const geo = req.geo;  // { city, country, region, latitude, longitude }
  const url = req.nextUrl.clone();

  // Geo-based routing
  if (geo?.country === 'DE' || geo?.country === 'AT' || geo?.country === 'CH') {
    url.pathname = `/de${url.pathname}`;
    return NextResponse.rewrite(url);
  }

  // A/B testing with cookie persistence
  const abCookie = req.cookies.get('ab-variant');
  let variant = abCookie?.value;

  if (!variant) {
    // Assign variant based on consistent hashing
    variant = Math.random() < 0.5 ? 'control' : 'experiment';
  }

  // Rewrite to variant-specific page
  if (url.pathname === '/pricing') {
    url.pathname = `/pricing/${variant}`;
    const response = NextResponse.rewrite(url);
    if (!abCookie) {
      response.cookies.set('ab-variant', variant, {
        maxAge: 60 * 60 * 24 * 30,  // 30 days
        httpOnly: true,
      });
    }
    return response;
  }

  // Add geo headers for server components
  const response = NextResponse.next();
  response.headers.set('x-user-country', geo?.country || 'US');
  response.headers.set('x-user-city', geo?.city || 'Unknown');
  return response;
}
```

```typescript
// app/pricing/[variant]/page.tsx
export default function PricingPage({ params }: { params: { variant: string } }) {
  const isExperiment = params.variant === 'experiment';
  return isExperiment ? <NewPricingPage /> : <OldPricingPage />;
}

// Generate both variants at build time
export function generateStaticParams() {
  return [{ variant: 'control' }, { variant: 'experiment' }];
}
```

Middleware runs before the request reaches your application code. `NextResponse.rewrite` changes the internal routing without changing the URL the user sees. Cookie-based variant assignment ensures users see the same variant consistently.

WebSockets provide full-duplex real-time communication. A robust implementation needs reconnection logic, heartbeat pings, and message queuing.

```typescript
// lib/ws-client.ts
type WSMessage = { type: string; payload: any };
type WSHandler = (data: WSMessage) => void;

export class ReconnectingWebSocket {
  private ws: WebSocket | null = null;
  private url: string;
  private handlers = new Map<string, Set<WSHandler>>();
  private reconnectAttempts = 0;
  private maxReconnects = 10;
  private messageQueue: WSMessage[] = [];
  private heartbeatInterval: ReturnType<typeof setInterval> | null = null;

  constructor(url: string) {
    this.url = url;
    this.connect();
  }

  private connect() {
    this.ws = new WebSocket(this.url);

    this.ws.onopen = () => {
      console.log('WebSocket connected');
      this.reconnectAttempts = 0;
      this.flushQueue();
      this.startHeartbeat();
    };

    this.ws.onmessage = (event) => {
      const data: WSMessage = JSON.parse(event.data);
      if (data.type === 'pong') return;  // Heartbeat response
      const handlers = this.handlers.get(data.type);
      handlers?.forEach(handler => handler(data));
    };

    this.ws.onclose = (event) => {
      this.stopHeartbeat();
      if (!event.wasClean && this.reconnectAttempts < this.maxReconnects) {
        const delay = Math.min(1000 * Math.pow(2, this.reconnectAttempts), 30000);
        console.log(`Reconnecting in ${delay}ms (attempt ${this.reconnectAttempts + 1})`);
        setTimeout(() => {
          this.reconnectAttempts++;
          this.connect();
        }, delay);
      }
    };

    this.ws.onerror = (error) => console.error('WebSocket error:', error);
  }

  private startHeartbeat() {
    this.heartbeatInterval = setInterval(() => {
      this.send({ type: 'ping', payload: {} });
    }, 30000);
  }

  private stopHeartbeat() {
    if (this.heartbeatInterval) clearInterval(this.heartbeatInterval);
  }

  private flushQueue() {
    while (this.messageQueue.length > 0) {
      const msg = this.messageQueue.shift()!;
      this.ws?.send(JSON.stringify(msg));
    }
  }

  send(message: WSMessage) {
    if (this.ws?.readyState === WebSocket.OPEN) {
      this.ws.send(JSON.stringify(message));
    } else {
      this.messageQueue.push(message);
    }
  }

  on(type: string, handler: WSHandler) {
    if (!this.handlers.has(type)) this.handlers.set(type, new Set());
    this.handlers.get(type)!.add(handler);
    return () => this.handlers.get(type)?.delete(handler);
  }

  close() {
    this.maxReconnects = 0;
    this.ws?.close();
  }
}
```

Exponential backoff prevents thundering herd on server restarts. The message queue ensures messages sent during reconnection aren't lost. Heartbeat pings detect dead connections that `onclose` wouldn't catch (e.g., network cable unplugged).

SSE provides server-to-client streaming over HTTP. Simpler than WebSockets when you only need one-way data flow (notifications, live updates, AI streaming).

```typescript
// app/api/events/route.ts
export const runtime = 'nodejs';  // SSE requires Node.js runtime

export async function GET(req: Request) {
  const encoder = new TextEncoder();

  const stream = new ReadableStream({
    async start(controller) {
      // Send initial connection event
      controller.enqueue(encoder.encode('event: connected\ndata: {}\n\n'));

      // Simulate real-time updates
      const interval = setInterval(() => {
        const data = JSON.stringify({
          timestamp: new Date().toISOString(),
          value: Math.random(),
        });
        controller.enqueue(encoder.encode(`data: ${data}\n\n`));
      }, 1000);

      // Clean up when client disconnects
      req.signal.addEventListener('abort', () => {
        clearInterval(interval);
        controller.close();
      });
    },
  });

  return new Response(stream, {
    headers: {
      'Content-Type': 'text/event-stream',
      'Cache-Control': 'no-cache',
      'Connection': 'keep-alive',
    },
  });
}
```

**Client-side consumption:**
```typescript
// hooks/use-sse.ts
import { useEffect, useState, useCallback } from 'react';

export function useSSE<T>(url: string) {
  const [data, setData] = useState<T | null>(null);
  const [error, setError] = useState<Error | null>(null);
  const [isConnected, setIsConnected] = useState(false);

  useEffect(() => {
    const eventSource = new EventSource(url);

    eventSource.onopen = () => setIsConnected(true);

    eventSource.onmessage = (event) => {
      try {
        const parsed = JSON.parse(event.data);
        setData(parsed);
      } catch (e) {
        setError(e as Error);
      }
    };

    eventSource.addEventListener('connected', () => {
      console.log('SSE connected');
    });

    eventSource.onerror = () => {
      setIsConnected(false);
      // EventSource auto-reconnects
    };

    return () => eventSource.close();
  }, [url]);

  return { data, error, isConnected };
}

// Usage
function LiveDashboard() {
  const { data, isConnected } = useSSE<{ timestamp: string; value: number }>('/api/events');
  return <div>{isConnected ? `Value: ${data?.value}` : 'Connecting...'}</div>;
}
```

SSE auto-reconnects on connection loss. Use named events (`event: type\n`) to multiplex different event types on one connection. SSE uses regular HTTP — works through proxies and load balancers without special configuration, unlike WebSockets.

Three approaches to real-time data with different complexity and use case fits.

**WebSockets — full-duplex:**
```typescript
// Client
const ws = new WebSocket('wss://api.myapp.com/ws');
ws.send(JSON.stringify({ type: 'subscribe', channel: 'orders' }));
ws.onmessage = (event) => console.log(JSON.parse(event.data));
```

**Server-Sent Events — server-to-client only:**
```typescript
// Client
const source = new EventSource('/api/events');
source.onmessage = (event) => console.log(JSON.parse(event.data));
// Auto-reconnects, uses standard HTTP
```

**HTTP Polling — simplest:**
```typescript
// Client
useEffect(() => {
  const interval = setInterval(async () => {
    const res = await fetch('/api/updates?since=' + lastTimestamp);
    const data = await res.json();
    if (data.length > 0) setUpdates(prev => [...prev, ...data]);
  }, 5000);
  return () => clearInterval(interval);
}, []);
```

| Feature | WebSocket | SSE | HTTP Polling |
|---------|-----------|-----|--------------|
| Direction | Bidirectional | Server → Client | Client → Server → Client |
| Connection | Persistent | Persistent | New per request |
| Auto-reconnect | Manual | Built-in | N/A |
| Binary data | Yes | No (text only) | Yes |
| HTTP/2 multiplexing | No | Yes | Yes |
| Proxy support | Requires upgrade | Standard HTTP | Standard HTTP |
| Server complexity | High | Low | Lowest |
| Scale | Hardest | Medium | Easiest |
| Use cases | Chat, gaming, collaboration | Notifications, feeds, AI streaming | Dashboards, status checks |

**Choose WebSocket** for: chat apps, collaborative editing, gaming — anything needing bidirectional communication. **Choose SSE** for: notifications, live feeds, AI token streaming — when the server pushes updates. **Choose polling** for: dashboards with 5-30s refresh intervals, simple status pages.

Web Workers run JavaScript in a separate thread, preventing heavy computation from blocking the UI. They communicate via message passing.

```typescript
// workers/data-processor.ts
self.onmessage = (event: MessageEvent<{ data: number[]; operation: string }>) => {
  const { data, operation } = event.data;

  let result: number[];
  switch (operation) {
    case 'sort':
      result = [...data].sort((a, b) => a - b);
      break;
    case 'filter-primes':
      result = data.filter(isPrime);
      break;
    case 'heavy-transform':
      result = data.map(n => {
        // Simulate expensive computation
        let val = n;
        for (let i = 0; i < 10000; i++) {
          val = Math.sqrt(val * val + i);
        }
        return Math.round(val);
      });
      break;
    default:
      result = data;
  }

  self.postMessage({ result, operation });
};

function isPrime(n: number): boolean {
  if (n < 2) return false;
  for (let i = 2; i <= Math.sqrt(n); i++) {
    if (n % i === 0) return false;
  }
  return true;
}

export {};  // Make it a module
```

```typescript
// hooks/use-worker.ts
import { useRef, useEffect, useCallback, useState } from 'react';

export function useWorker<TInput, TOutput>(
  workerFactory: () => Worker
) {
  const workerRef = useRef<Worker | null>(null);
  const [result, setResult] = useState<TOutput | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  useEffect(() => {
    workerRef.current = workerFactory();
    workerRef.current.onmessage = (event: MessageEvent<TOutput>) => {
      setResult(event.data);
      setIsProcessing(false);
    };
    return () => workerRef.current?.terminate();
  }, [workerFactory]);

  const postMessage = useCallback((data: TInput) => {
    setIsProcessing(true);
    workerRef.current?.postMessage(data);
  }, []);

  return { result, isProcessing, postMessage };
}

// Usage in component
function DataProcessor() {
  const { result, isProcessing, postMessage } = useWorker<
    { data: number[]; operation: string },
    { result: number[]; operation: string }
  >(() => new Worker(new URL('../workers/data-processor.ts', import.meta.url)));

  return (
    <button onClick={() => postMessage({ data: largeArray, operation: 'sort' })}>
      {isProcessing ? 'Processing...' : `Sort (${result?.result.length ?? 0} items)`}
    </button>
  );
}
```

Workers cannot access the DOM, `window`, or `document`. Use `Transferable` objects (ArrayBuffer) for large data to avoid copying: `worker.postMessage(data, [buffer])`. Vite and webpack handle worker bundling with the `new URL()` syntax.

WebAssembly (WASM) runs compiled code in the browser at near-native speed. Rust compiles to WASM via `wasm-pack`.

**Rust WASM module:**
```rust
// src/lib.rs
use wasm_bindgen::prelude::*;

#[wasm_bindgen]
pub fn fibonacci(n: u32) -> u64 {
    match n {
        0 => 0,
        1 => 1,
        _ => {
            let mut a: u64 = 0;
            let mut b: u64 = 1;
            for _ in 2..=n {
                let temp = a + b;
                a = b;
                b = temp;
            }
            b
        }
    }
}

#[wasm_bindgen]
pub fn process_image(data: &[u8], width: u32, height: u32) -> Vec<u8> {
    // Grayscale conversion
    let mut output = Vec::with_capacity((width * height) as usize * 4);
    for chunk in data.chunks(4) {
        let gray = (0.299 * chunk[0] as f64
            + 0.587 * chunk[1] as f64
            + 0.114 * chunk[2] as f64) as u8;
        output.extend_from_slice(&[gray, gray, gray, chunk[3]]);
    }
    output
}
```

**Build:**
```bash
cargo install wasm-pack
wasm-pack build --target web
```

**JavaScript usage:**
```typescript
import init, { fibonacci, process_image } from './pkg/my_wasm_module.js';

async function main() {
  // Initialize WASM module
  await init();

  // Use functions
  const result = fibonacci(50);
  console.log(`fib(50) = ${result}`); // 12586269025

  // Process image data
  const canvas = document.createElement('canvas');
  const ctx = canvas.getContext('2d')!;
  const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
  const grayscale = process_image(
    new Uint8Array(imageData.data.buffer),
    canvas.width,
    canvas.height
  );
  const newImageData = new ImageData(
    new Uint8ClampedArray(grayscale),
    canvas.width,
    canvas.height
  );
  ctx.putImageData(newImageData, 0, 0);
}
```

WASM is ideal for: image/video processing, cryptography, physics simulations, and data parsing. For simple operations, the overhead of crossing the JS-WASM boundary negates the speed gain. Use WASM when the computation itself is the bottleneck.

FlatList is React Native's virtualized list component. Poor usage causes jank, blank areas, and excessive re-renders.

**Common performance issues and fixes:**

```tsx
import { FlatList, View, Text } from 'react-native';
import { memo, useCallback, useMemo } from 'react';

// BAD: Inline render function creates new reference each render
<FlatList
  data={items}
  renderItem={({ item }) => <ItemCard item={item} />}  // Re-creates every render
/>

// GOOD: Extract and memoize
const renderItem = useCallback(({ item }: { item: Item }) => (
  <MemoizedItemCard item={item} />
), []);

// Memoize the item component
const MemoizedItemCard = memo(function ItemCard({ item }: { item: Item }) {
  return (
    <View style={{ padding: 16, borderBottomWidth: 1, borderColor: '#eee' }}>
      <Text style={{ fontSize: 16, fontWeight: '600' }}>{item.title}</Text>
      <Text style={{ color: '#666', marginTop: 4 }}>{item.description}</Text>
    </View>
  );
});
```

**Optimized FlatList configuration:**
```tsx
<FlatList
  data={items}
  renderItem={renderItem}
  keyExtractor={useCallback((item: Item) => item.id, [])}
  // Performance props
  removeClippedSubviews={true}           // Detach off-screen views
  maxToRenderPerBatch={10}               // Items per render batch
  updateCellsBatchingPeriod={50}         // ms between batch renders
  windowSize={5}                         // Render 5 screens worth
  initialNumToRender={10}                // Initial render count
  getItemLayout={useCallback(             // Skip measurement if items have fixed height
    (_: any, index: number) => ({
      length: ITEM_HEIGHT,
      offset: ITEM_HEIGHT * index,
      index,
    }),
    []
  )}
  // Avoid layout thrashing
  contentContainerStyle={useMemo(() => ({ paddingBottom: 20 }), [])}
/>
```

**Key rules:** (1) Never create objects/functions inline in `renderItem` or `style` props. (2) Use `memo()` on item components. (3) Always provide `keyExtractor`. (4) Use `getItemLayout` when items have known fixed heights — it eliminates async measurement. (5) `removeClippedSubviews={true}` saves memory on Android.

Sensitive data like auth tokens and API keys must be stored in the platform's secure enclave, not AsyncStorage. `expo-secure-store` uses iOS Keychain and Android Keystore.

```bash
npx expo install expo-secure-store
```

```typescript
// lib/secure-storage.ts
import * as SecureStore from 'expo-secure-store';
import { Platform } from 'react-native';

const TOKEN_KEY = 'auth_token';
const REFRESH_KEY = 'refresh_token';

export const secureStorage = {
  async setToken(token: string): Promise<void> {
    await SecureStore.setItemAsync(TOKEN_KEY, token, {
      keychainAccessible: SecureStore.AFTER_FIRST_UNLOCK,
    });
  },

  async getToken(): Promise<string | null> {
    return SecureStore.getItemAsync(TOKEN_KEY);
  },

  async setRefreshToken(token: string): Promise<void> {
    await SecureStore.setItemAsync(REFRESH_KEY, token, {
      keychainAccessible: SecureStore.AFTER_FIRST_UNLOCK,
    });
  },

  async getRefreshToken(): Promise<string | null> {
    return SecureStore.getItemAsync(REFRESH_KEY);
  },

  async clearTokens(): Promise<void> {
    await SecureStore.deleteItemAsync(TOKEN_KEY);
    await SecureStore.deleteItemAsync(REFRESH_KEY);
  },
};

// Auth context with secure storage
import { createContext, useContext, useEffect, useState } from 'react';

const AuthContext = createContext<{
  token: string | null;
  signIn: (token: string, refreshToken: string) => Promise<void>;
  signOut: () => Promise<void>;
  isLoading: boolean;
}>(null!);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [token, setToken] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    secureStorage.getToken().then(t => {
      setToken(t);
      setIsLoading(false);
    });
  }, []);

  const signIn = async (token: string, refreshToken: string) => {
    await secureStorage.setToken(token);
    await secureStorage.setRefreshToken(refreshToken);
    setToken(token);
  };

  const signOut = async () => {
    await secureStorage.clearTokens();
    setToken(null);
  };

  return (
    <AuthContext.Provider value={{ token, signIn, signOut, isLoading }}>
      {children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => useContext(AuthContext);
```

`AFTER_FIRST_UNLOCK` makes the token available after the first device unlock (recommended for background fetch). SecureStore has a 2KB value limit — store only tokens, not large data. On web (Expo for Web), SecureStore falls back to `localStorage` — use a web-specific secure alternative if needed.

Durable Objects provide strongly consistent, stateful coordination at the edge. Each object has a unique ID and its own storage, running in a single location.

```typescript
// src/counter.ts — Durable Object class
export class Counter {
  private state: DurableObjectState;
  private value: number = 0;

  constructor(state: DurableObjectState) {
    this.state = state;
    // Load persisted value
    this.state.blockConcurrencyWhile(async () => {
      this.value = (await this.state.storage.get<number>('value')) || 0;
    });
  }

  async fetch(request: Request): Promise<Response> {
    const url = new URL(request.url);

    switch (url.pathname) {
      case '/increment': {
        this.value++;
        await this.state.storage.put('value', this.value);
        return new Response(JSON.stringify({ value: this.value }));
      }
      case '/decrement': {
        this.value--;
        await this.state.storage.put('value', this.value);
        return new Response(JSON.stringify({ value: this.value }));
      }
      case '/value': {
        return new Response(JSON.stringify({ value: this.value }));
      }
      default:
        return new Response('Not found', { status: 404 });
    }
  }
}
```

```typescript
// src/index.ts — Worker entry point
interface Env {
  COUNTER: DurableObjectNamespace;
}

export default {
  async fetch(request: Request, env: Env): Promise<Response> {
    const url = new URL(request.url);
    const counterId = url.searchParams.get('id') || 'default';

    // Get or create a Durable Object instance
    const id = env.COUNTER.idFromName(counterId);
    const obj = env.COUNTER.get(id);

