SharedWorker runs a single instance shared across all tabs of the same origin. Useful for WebSocket connections, caching, and tab synchronization.

```typescript
// workers/shared-worker.ts
const connections: MessagePort[] = [];
let sharedState = { count: 0, lastUpdate: '' };

self.onconnect = (event: MessageEvent) => {
  const port = event.ports[0];
  connections.push(port);

  // Send current state to new connection
  port.postMessage({ type: 'init', state: sharedState });

  port.onmessage = (e: MessageEvent) => {
    const { type, payload } = e.data;

    switch (type) {
      case 'increment':
        sharedState.count++;
        sharedState.lastUpdate = new Date().toISOString();
        broadcast({ type: 'state-update', state: sharedState });
        break;

      case 'get-state':
        port.postMessage({ type: 'state-update', state: sharedState });
        break;
    }
  };

  port.onclose = () => {
    const index = connections.indexOf(port);
    if (index > -1) connections.splice(index, 1);
  };

  port.start();
};

function broadcast(message: any) {
  connections.forEach(port => {
    try {
      port.postMessage(message);
    } catch {
      // Port might be closed
    }
  });
}
```

```typescript
// hooks/use-shared-worker.ts
import { useEffect, useState, useRef } from 'react';

export function useSharedWorker<T>(
  workerUrl: string
): { state: T | null; send: (message: any) => void } {
  const [state, setState] = useState<T | null>(null);
  const workerRef = useRef<SharedWorker | null>(null);

  useEffect(() => {
    workerRef.current = new SharedWorker(workerUrl);
    const port = workerRef.current.port;

    port.onmessage = (event) => {
      if (event.data.type === 'state-update' || event.data.type === 'init') {
        setState(event.data.state);
      }
    };

    port.start();
    return () => port.close();
  }, [workerUrl]);

  const send = (message: any) => {
    workerRef.current?.port.postMessage(message);
  };

  return { state, send };
}

// Usage — all tabs share the same counter
function Counter() {
  const { state, send } = useSharedWorker<{ count: number }>('/shared-worker.js');
  return (
    <button onClick={() => send({ type: 'increment' })}>
      Count: {state?.count ?? 0} (synced across tabs)
    </button>
  );
}
```

SharedWorker is ideal for: single WebSocket connection shared across tabs, cross-tab state sync, and preventing duplicate API requests. Note: SharedWorker is not supported in Safari on iOS. Use BroadcastChannel as a fallback for tab communication.

