const hash = await crypto.subtle.digest(
  'SHA-256',
  new TextEncoder().encode('hello')
);
const hashHex = [...new Uint8Array(hash)]
  .map(b => b.toString(16).padStart(2, '0'))
  .join('');

// Random values
