Reanimated 3 runs animations on the UI thread for 60fps performance. Combined with Gesture Handler, it creates fluid interactive animations.

```bash
npx expo install react-native-reanimated react-native-gesture-handler
```

```typescript
// Swipeable card with spring animation
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  withSpring,
  withTiming,
  runOnJS,
  interpolate,
  Extrapolation,
} from 'react-native-reanimated';
import { Gesture, GestureDetector } from 'react-native-gesture-handler';
import { Dimensions } from 'react-native';

const SCREEN_WIDTH = Dimensions.get('window').width;
const SWIPE_THRESHOLD = SCREEN_WIDTH * 0.3;

export function SwipeableCard({ onSwipeLeft, onSwipeRight, children }) {
  const translateX = useSharedValue(0);
  const translateY = useSharedValue(0);

  const gesture = Gesture.Pan()
    .onUpdate((event) => {
      translateX.value = event.translationX;
      translateY.value = event.translationY * 0.5;  // Dampened vertical
    })
    .onEnd((event) => {
      if (Math.abs(event.translationX) > SWIPE_THRESHOLD) {
        // Swipe out
        const direction = event.translationX > 0 ? 1 : -1;
        translateX.value = withTiming(direction * SCREEN_WIDTH * 1.5, { duration: 300 });
        runOnJS(direction > 0 ? onSwipeRight : onSwipeLeft)();
      } else {
        // Spring back
        translateX.value = withSpring(0, { damping: 15, stiffness: 150 });
        translateY.value = withSpring(0, { damping: 15, stiffness: 150 });
      }
    });

  const animatedStyle = useAnimatedStyle(() => {
    const rotate = interpolate(
      translateX.value,
      [-SCREEN_WIDTH, 0, SCREEN_WIDTH],
      [-15, 0, 15],
      Extrapolation.CLAMP
    );

    return {
      transform: [
        { translateX: translateX.value },
        { translateY: translateY.value },
        { rotate: `${rotate}deg` },
      ],
      opacity: interpolate(
        Math.abs(translateX.value),
        [0, SCREEN_WIDTH * 0.5],
        [1, 0.5],
        Extrapolation.CLAMP
      ),
    };
  });

  return (
    <GestureDetector gesture={gesture}>
      <Animated.View style={[styles.card, animatedStyle]}>
        {children}
      </Animated.View>
    </GestureDetector>
  );
}
```

`useSharedValue` stores values on the UI thread. `useAnimatedStyle` computes styles on the UI thread. `withSpring` and `withTiming` are UI-thread animations. `runOnJS` bridges back to the JavaScript thread for callbacks. This architecture ensures animations never drop frames.

Offline-first apps store data locally and sync when connectivity returns. Use SQLite for local storage and a sync queue for pending changes.

```bash
npx expo install expo-sqlite @react-native-community/netinfo
```

```typescript
// lib/local-db.ts
import * as SQLite from 'expo-sqlite';

const db = SQLite.openDatabaseSync('myapp.db');

// Initialize tables
db.execSync(`
  CREATE TABLE IF NOT EXISTS items (
    id TEXT PRIMARY KEY,
    data TEXT NOT NULL,
    updated_at INTEGER NOT NULL,
    synced INTEGER DEFAULT 0
  );
  CREATE TABLE IF NOT EXISTS sync_queue (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    operation TEXT NOT NULL,
    table_name TEXT NOT NULL,
    record_id TEXT NOT NULL,
    payload TEXT NOT NULL,
    created_at INTEGER NOT NULL
  );
`);

export function saveItem(item: { id: string; data: any }) {
  const now = Date.now();
  db.runSync(
    'INSERT OR REPLACE INTO items (id, data, updated_at, synced) VALUES (?, ?, ?, 0)',
    [item.id, JSON.stringify(item.data), now]
  );

  // Queue for sync
  db.runSync(
    'INSERT INTO sync_queue (operation, table_name, record_id, payload, created_at) VALUES (?, ?, ?, ?, ?)',
    ['upsert', 'items', item.id, JSON.stringify(item.data), now]
  );
}

export function getItems(): any[] {
  return db.getAllSync('SELECT * FROM items ORDER BY updated_at DESC').map(row => ({
    ...row,
    data: JSON.parse(row.data as string),
  }));
}
```

```typescript
// lib/sync-manager.ts
import NetInfo from '@react-native-community/netinfo';

export class SyncManager {
  private isSyncing = false;

  constructor() {
    // Listen for connectivity changes
    NetInfo.addEventListener(state => {
      if (state.isConnected && !this.isSyncing) {
        this.sync();
      }
    });
  }

  async sync() {
    this.isSyncing = true;
    try {
      const pending = db.getAllSync(
        'SELECT * FROM sync_queue ORDER BY created_at ASC LIMIT 50'
      );

      for (const item of pending) {
        try {
          await fetch(`${API_URL}/sync`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              operation: item.operation,
              table: item.table_name,
              id: item.record_id,
              data: JSON.parse(item.payload as string),
            }),
          });

          // Mark as synced
          db.runSync('DELETE FROM sync_queue WHERE id = ?', [item.id]);
          db.runSync('UPDATE items SET synced = 1 WHERE id = ?', [item.record_id]);
        } catch {
          break;  // Stop on first failure, retry later
        }
      }
    } finally {
      this.isSyncing = false;
    }
  }
}
```

The sync queue pattern: write locally first, queue the operation, sync when online. Use `updated_at` timestamps for conflict resolution (last-write-wins). For complex conflict resolution, consider CRDTs or operational transform.

