```typescript
// app/_layout.tsx — Handle incoming links
import { useEffect } from 'react';
import { Linking } from 'react-native';
import { useRouter } from 'expo-router';
import * as Notifications from 'expo-notifications';

export default function RootLayout() {
  const router = useRouter();

  useEffect(() => {
    // Handle link when app is already open
    const subscription = Linking.addEventListener('url', ({ url }) => {
      handleDeepLink(url);
    });

    // Handle link that opened the app
    Linking.getInitialURL().then(url => {
      if (url) handleDeepLink(url);
    });

    return () => subscription.remove();
  }, []);

  function handleDeepLink(url: string) {
    const parsed = Linking.parse(url);
    // myapp://user/123 → { path: 'user/123', queryParams: {} }
    // https://myapp.com/app/user/123 → { path: 'app/user/123', queryParams: {} }

    if (parsed.path?.startsWith('user/')) {
      const userId = parsed.path.split('/')[1];
      router.push(`/user/${userId}`);
    } else if (parsed.path === 'settings') {
      router.push('/settings');
    }
  }

  return <Stack />;
}
```

